final:
module RefModule (
    input D, C, E, R,
    output Q
);

reg Q_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge C or posedge dbg_halt) begin
    if (R == 0) begin
        Q_reg <= 0;
    end else if (E == 1) begin
        Q_reg <= D;
    end
end

assign Q = Q_reg;

endmodule
